Hi, thanks for the comment. The article you linked is a little old and since then the `PropertyMock` class has been bundled into the `mock` module. It is now more straight forward to mock properties as this example code shows:

    from math import pi, sqrt
    from mock import PropertyMock, patch
    
    
    class Rectangle(object):
        def __init__(self, width, height):
            self.width = width
            self.height = height
    
        @property
        def area(self):
            return self.width * self.height
    
    
    class Circle(object):
        def __init__(self, radius):
            self.radius = radius
    
        @property
        def area(self):
            return self.radius * self.radius * pi
    
        @area.setter
        def area(self, value):
            self.radius = sqrt(value / pi)
    
    
    def test_patch_rectangle_get_area():
        r = Rectangle(10, 10)
    
        assert r.area == 100
    
        with patch.object(Rectangle, "area", new_callable=PropertyMock, return_value=500) as mock_area:
            assert r.area == 500  # return value from the mock
    
        mock_area.assert_called_once_with()  # and the call was recorded
    
    
    def test_patch_circle_set_area():
        c = Circle(10)
    
        c.area = 81 * pi
        assert c.radius == 9
    
        with patch.object(Circle, "area", new_callable=PropertyMock) as mock_area:
            c.area = 10
    
        assert c.area == 81 * pi  # Area not changed because it was patched
        mock_area.assert_called_once_with(10)  # but the call was recorded

